    public partial class EmployeeEducationService : BaseService<EmployeeEducation>, IEmployeeEducationService
    {
        public EmployeeEducationService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task<EmployeeEducation> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<EmployeeEducation>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<EmployeeEducation>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<EmployeeEducation>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Qualification.Contains(search.Name)
                     || x.Degree.Contains(search.Name)
                     || x.Medium.Contains(search.Name))
                     && x.EmployeeId == search.RefId.Value,
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Qualification", ascending: !search.IsDescend);
        }
    }
